def patchify(image, patch_size):
    """Slice an (H, W, C) image into non-overlapping flattened patches."""
    H = len(image)
    W = len(image[0])
    C = len(image[0][0])
    P = patch_size
    if H % P != 0 or W % P != 0:
        raise ValueError(
            f"image dims ({H}, {W}) must be divisible by patch_size {P}"
        )
    patches = []
    for i in range(0, H, P):
        for j in range(0, W, P):
            patch = []
            for di in range(P):
                for dj in range(P):
                    patch.extend(image[i + di][j + dj])
            patches.append(patch)
    return patches, (H // P, W // P)
